    "programmeId": "HKU-UG-6999-125",
    "majorId": "HKU-UG-6999-125-M1",
    "courseCode": "COMP3523",
    "titleEn": "Security and Privacy in Artificial Intelligence",
    "titleZh": "Security and Privacy in Artificial Intelligence",
    "credits": 6,
    "recommendedYear": 2,
    "semester": "1",
    "courseType": "major_elective",
    "prerequisites": "COMP3314",
    "exclusions": "None",
    "description": "This course will equip students with the knowledge and hands-on experience to develop secure, privacy-\u0002preserving AI systems. As AI becomes increasingly integrated into our everyday lives, students will explore how seemingly powerful AI systems can be compromised through various attacks that manipulate decision-making processes and steal private information. Students will also learn about cutting-edge defenses designed to protect these systems. By the end of the course, students will be able to assess security and privacy risks when designing AI-driven solutions and implement effective countermeasures.",
    "sourceUrl": "https://www.cs.hku.hk/index.php/programmes/course-offered?infile=2025/comp3523.html",
